class Real:
    def request(self):
        print("real")
        return 1

class Proxy:
    def __init__(self, real):
        self.real = real
        self.cache = None
    def request(self):
        if self.cache is None:
            self.cache = self.real.request()
        else:
            print("cached")
        return self.cache

p = Proxy(Real())
p.request()
p.request()

